class CheckersBoard:
    def __init__(self):
        self.board = self._initialize_board()

    def _initialize_board(self):
        board = [[' ' for _ in range(8)] for _ in range(8)]
        for i in range(0, 3):
            for j in (1, 3, 5, 7):
                board[i][j] = 'B'
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                board[i][j] = 'W'
        return board

    def display_board(self):
        print('  a b c d e f g h')
        for row_idx, row in enumerate(self.board, start=1):
            print(f'{row_idx} {" ".join(row)}')

    def move_piece(self, from_pos, to_pos):
        x_from, y_from = ord(from_pos[0]) - ord('a'), int(from_pos[1]) - 1
        x_to, y_to = ord(to_pos[0]) - ord('a'), int(to_pos[1]) - 1
        if self.board[x_from][y_from] != ' ':
            self.board[x_to][y_to] = self.board[x_from][y_from]
            self.board[x_from][y_from] = ' '
