from .CheckersBoard import CheckersBoard
from .Player import Player

class Game:
    def __init__(self):
        self.board = CheckersBoard()
        self.players = [Player("White", "W"), Player("Black", "B")]
        self.current_player_index = 0

    def switch_turn(self):
        self.current_player_index = (self.current_player_index + 1) % 2

    def play(self):
        while True:
            self.board.display_board()
            move = input(f"{self.players[self.current_player_index].name}'s turn. Enter move: ")
            if move.lower() in ['quit', 'exit']:
                print("Game exited.")
                break
            try:
                from_pos, to_pos = move.split('-')
                self.board.move_piece(from_pos, to_pos)
                self.switch_turn()
            except Exception as e:
                print(f"Invalid move: {e}")
